-- Create table
CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT NOT NULL, sku TEXT UNIQUE, price REAL, qty INTEGER);

-- Insert samples
INSERT INTO products (name, sku, price, qty) VALUES ('Acme Widget','AW-100',12.99,100);
INSERT INTO products (name, sku, price, qty) VALUES ('Blue Gadget','BG-200',9.5,50);
INSERT INTO products (name, sku, price, qty) VALUES ('Clear Cable','CC-300',4.25,250);

-- Read
SELECT * FROM products ORDER BY name;

-- Update (example)
UPDATE products SET qty = qty - 1 WHERE sku = 'AW-100';

-- Delete (example)
DELETE FROM products WHERE sku = 'CC-300';
